// Calcula ranking, indice general y alertas a partir de las filas del Sheet
const filas = $input.all().map(i => i.json);

const porVendedor = {};
for (const f of filas) {
  if (String(f.validado).toLowerCase() !== 'si') continue; // control humano: solo cuentan puntos validados por el supervisor
  const v = f.vendedor;
  if (!porVendedor[v]) porVendedor[v] = { vendedor: v, zona: f.zona, aperturas: 0, recompras: 0, ventas: 0 };
  if (Number(f.monto_bs) >= 300 && f.estado === 'primer_pedido') porVendedor[v].aperturas++;
  if (f.estado === 'recompra') porVendedor[v].recompras++;
  porVendedor[v].ventas += Number(f.monto_bs) || 0;
}

const ranking = Object.values(porVendedor)
  .map(v => ({ ...v, indice: Math.round(v.aperturas * 20 + v.recompras * 35 + v.ventas / 30) }))
  .sort((a, b) => b.indice - a.indice);

// Alertas: puntos validados con mas de 15 dias sin recompra
const alertas = filas
  .filter(f => String(f.validado).toLowerCase() === 'si' && Number(f.dias_sin_recompra) > 15)
  .map(f => `${f.punto} (${f.vendedor}, ${f.zona}): ${f.dias_sin_recompra} dias sin recompra`);

const totales = {
  puntos_abiertos: ranking.reduce((s, v) => s + v.aperturas, 0),
  ventas_bs: ranking.reduce((s, v) => s + v.ventas, 0),
  meta_trimestral: 250
};

return [{ json: { ranking, alertas, totales, fecha: new Date().toISOString().slice(0, 10) } }];

